-- =====================================================
-- IMPORTACIÓN FOLIOS UIIE-2026 (Google Sheets → Supabase)
-- 489 registros | Generado 2026-04-21
-- Ejecutar en Supabase SQL Editor
-- =====================================================

BEGIN;

-- ── PASO 1: Tabla temporal de inspectores ──────────────────────────
CREATE TEMP TABLE _insp_map (nombre TEXT, uid UUID);
  SELECT 'Efraím Castellanos Frayre', id FROM public.usuarios
  WHERE LOWER(COALESCE(apellidos,'') || ' ' || nombre) ILIKE '%frayre%'
  ORDER BY CASE WHEN LOWER(COALESCE(apellidos,'')) ILIKE '%castellanos%' THEN 0 ELSE 1 END
  LIMIT 1;
  SELECT 'Joaquin Corella Puente', id FROM public.usuarios
  WHERE LOWER(COALESCE(apellidos,'') || ' ' || nombre) ILIKE '%puente%'
  ORDER BY CASE WHEN LOWER(COALESCE(apellidos,'')) ILIKE '%corella%' THEN 0 ELSE 1 END
  LIMIT 1;
  SELECT 'Erick Andrés Aguirre Prieto', id FROM public.usuarios
  WHERE LOWER(COALESCE(apellidos,'') || ' ' || nombre) ILIKE '%prieto%'
  ORDER BY CASE WHEN LOWER(COALESCE(apellidos,'')) ILIKE '%aguirre%' THEN 0 ELSE 1 END
  LIMIT 1;
  SELECT 'Hugo Díaz García', id FROM public.usuarios
  WHERE LOWER(COALESCE(apellidos,'') || ' ' || nombre) ILIKE '%garcía%'
  ORDER BY CASE WHEN LOWER(COALESCE(apellidos,'')) ILIKE '%díaz%' THEN 0 ELSE 1 END
  LIMIT 1;
  SELECT 'Aldo Ramírez Montoya', id FROM public.usuarios
  WHERE LOWER(COALESCE(apellidos,'') || ' ' || nombre) ILIKE '%montoya%'
  ORDER BY CASE WHEN LOWER(COALESCE(apellidos,'')) ILIKE '%ramírez%' THEN 0 ELSE 1 END
  LIMIT 1;
  SELECT 'Jesus Antonio Rodriguez de Ita', id FROM public.usuarios
  WHERE LOWER(COALESCE(apellidos,'') || ' ' || nombre) ILIKE '%ita%'
  ORDER BY CASE WHEN LOWER(COALESCE(apellidos,'')) ILIKE '%de%' THEN 0 ELSE 1 END
  LIMIT 1;
  SELECT 'Eduardo Montelongo Moral', id FROM public.usuarios
  WHERE LOWER(COALESCE(apellidos,'') || ' ' || nombre) ILIKE '%moral%'
  ORDER BY CASE WHEN LOWER(COALESCE(apellidos,'')) ILIKE '%montelongo%' THEN 0 ELSE 1 END
  LIMIT 1;
  SELECT 'Luis Felipe Martinez Cerda', id FROM public.usuarios
  WHERE LOWER(COALESCE(apellidos,'') || ' ' || nombre) ILIKE '%cerda%'
  ORDER BY CASE WHEN LOWER(COALESCE(apellidos,'')) ILIKE '%martinez%' THEN 0 ELSE 1 END
  LIMIT 1;

-- Verify inspector matches (should be 8 rows):
-- SELECT * FROM _insp_map;

-- ── PASO 2: Tabla temporal con todos los datos del sheet ───────────
CREATE TEMP TABLE _folios_raw (
  folio_str  TEXT,
  folio_seq  INT,
  insp_nombre TEXT,
  integrador  TEXT,
  solicitante TEXT,
  kwp         NUMERIC,
  precio      NUMERIC,
  ciudad      TEXT,
  estado_mx   TEXT,
  fecha_est   DATE,
  created_ts  TIMESTAMPTZ
);


-- ── PASO 3: folios_lista_control ──────────────────────────────────
SELECT
  r.folio_str,
  r.folio_seq,
  true,
  m.uid,
  r.fecha_est,
  r.created_ts
FROM _folios_raw r
LEFT JOIN _insp_map m ON m.nombre = r.insp_nombre
ON CONFLICT (numero_folio) DO NOTHING;

-- ── PASO 4: solicitudes_folio ──────────────────────────────────────
   fecha_estimada, precio_propuesto, precio_base, porcentaje_precio,
   requiere_autorizacion, status, folio_asignado_id, notas_inspector,
   created_at, updated_at)
SELECT
  m.uid,
  r.solicitante,
  'moral',
  r.ciudad,
  r.estado_mx,
  r.kwp,
  r.fecha_est,
  r.precio,
  CASE
    WHEN r.kwp IS NULL OR r.kwp < 10 THEN 17000
    WHEN r.kwp < 20 THEN 18000
    WHEN r.kwp < 30 THEN 20000
    WHEN r.kwp < 40 THEN 22000
    WHEN r.kwp < 50 THEN 23000
    WHEN r.kwp < 70 THEN 25000
    WHEN r.kwp < 80 THEN 26000
    WHEN r.kwp < 90 THEN 27000
    WHEN r.kwp < 100 THEN 28000
    WHEN r.kwp < 125 THEN 30000
    WHEN r.kwp < 150 THEN 32000
    WHEN r.kwp < 200 THEN 34000
    WHEN r.kwp < 250 THEN 36000
    WHEN r.kwp < 300 THEN 38000
    WHEN r.kwp < 350 THEN 41000
    WHEN r.kwp < 400 THEN 44000
    WHEN r.kwp < 450 THEN 47000
    WHEN r.kwp < 500 THEN 50000
    ELSE 55000
  END AS precio_base,
  CASE
    WHEN r.precio IS NULL OR r.precio = 0 THEN 100
    WHEN r.kwp IS NULL OR r.kwp < 10 THEN ROUND((r.precio/17000.0)*100,2)
    WHEN r.kwp < 20 THEN ROUND((r.precio/18000.0)*100,2)
    WHEN r.kwp < 30 THEN ROUND((r.precio/20000.0)*100,2)
    WHEN r.kwp < 40 THEN ROUND((r.precio/22000.0)*100,2)
    WHEN r.kwp < 50 THEN ROUND((r.precio/23000.0)*100,2)
    WHEN r.kwp < 70 THEN ROUND((r.precio/25000.0)*100,2)
    WHEN r.kwp < 80 THEN ROUND((r.precio/26000.0)*100,2)
    WHEN r.kwp < 90 THEN ROUND((r.precio/27000.0)*100,2)
    WHEN r.kwp < 100 THEN ROUND((r.precio/28000.0)*100,2)
    WHEN r.kwp < 125 THEN ROUND((r.precio/30000.0)*100,2)
    WHEN r.kwp < 150 THEN ROUND((r.precio/32000.0)*100,2)
    WHEN r.kwp < 200 THEN ROUND((r.precio/34000.0)*100,2)
    WHEN r.kwp < 250 THEN ROUND((r.precio/36000.0)*100,2)
    WHEN r.kwp < 300 THEN ROUND((r.precio/38000.0)*100,2)
    WHEN r.kwp < 350 THEN ROUND((r.precio/41000.0)*100,2)
    WHEN r.kwp < 400 THEN ROUND((r.precio/44000.0)*100,2)
    WHEN r.kwp < 450 THEN ROUND((r.precio/47000.0)*100,2)
    WHEN r.kwp < 500 THEN ROUND((r.precio/50000.0)*100,2)
    ELSE ROUND((r.precio/55000.0)*100,2)
  END AS porcentaje_precio,
  CASE
    WHEN r.precio IS NULL OR r.precio = 0 THEN false
    WHEN r.kwp IS NULL OR r.kwp < 10 THEN (r.precio/17000.0) < 0.70
    WHEN r.kwp < 20 THEN (r.precio/18000.0) < 0.70
    WHEN r.kwp < 30 THEN (r.precio/20000.0) < 0.70
    WHEN r.kwp < 40 THEN (r.precio/22000.0) < 0.70
    WHEN r.kwp < 50 THEN (r.precio/23000.0) < 0.70
    WHEN r.kwp < 70 THEN (r.precio/25000.0) < 0.70
    WHEN r.kwp < 80 THEN (r.precio/26000.0) < 0.70
    WHEN r.kwp < 90 THEN (r.precio/27000.0) < 0.70
    WHEN r.kwp < 100 THEN (r.precio/28000.0) < 0.70
    WHEN r.kwp < 125 THEN (r.precio/30000.0) < 0.70
    WHEN r.kwp < 150 THEN (r.precio/32000.0) < 0.70
    WHEN r.kwp < 200 THEN (r.precio/34000.0) < 0.70
    WHEN r.kwp < 250 THEN (r.precio/36000.0) < 0.70
    WHEN r.kwp < 300 THEN (r.precio/38000.0) < 0.70
    WHEN r.kwp < 350 THEN (r.precio/41000.0) < 0.70
    WHEN r.kwp < 400 THEN (r.precio/44000.0) < 0.70
    WHEN r.kwp < 450 THEN (r.precio/47000.0) < 0.70
    WHEN r.kwp < 500 THEN (r.precio/50000.0) < 0.70
    ELSE (r.precio/55000.0) < 0.70
  END AS requiere_autorizacion,
  'folio_asignado',
  f.id,
  CASE WHEN r.integrador <> '' THEN ('Integrador: ' || r.integrador) ELSE NULL END,
  r.created_ts,
  NOW()
FROM _folios_raw r
LEFT JOIN _insp_map m ON m.nombre = r.insp_nombre
JOIN public.folios_lista_control f ON f.numero_folio = r.folio_str
WHERE NOT EXISTS (
  SELECT 1 FROM public.solicitudes_folio s WHERE s.folio_asignado_id = f.id
);

-- ── PASO 5: expedientes ────────────────────────────────────────────
   fecha_inicio, status, created_at, updated_at)
SELECT
  f.id,
  r.folio_str,
  m.uid,
  r.kwp,
  r.ciudad,
  r.estado_mx,
  r.fecha_est,
  'en_proceso',
  NOW(),
  NOW()
FROM _folios_raw r
LEFT JOIN _insp_map m ON m.nombre = r.insp_nombre
JOIN public.folios_lista_control f ON f.numero_folio = r.folio_str
WHERE NOT EXISTS (
  SELECT 1 FROM public.expedientes e WHERE e.numero_folio = r.folio_str
);

-- ── LIMPIEZA ───────────────────────────────────────────────────────
DROP TABLE _folios_raw;
DROP TABLE _insp_map;

-- ── VERIFICACIÓN ──────────────────────────────────────────────────
SELECT
  'folios_lista_control'  AS tabla, COUNT(*) FROM public.folios_lista_control WHERE numero_folio LIKE 'UIIE-%-2026'
UNION ALL SELECT 'solicitudes_folio', COUNT(*) FROM public.solicitudes_folio sf
  JOIN public.folios_lista_control f ON f.id = sf.folio_asignado_id WHERE f.numero_folio LIKE 'UIIE-%-2026'
UNION ALL SELECT 'expedientes', COUNT(*) FROM public.expedientes WHERE numero_folio LIKE 'UIIE-%-2026';

COMMIT;
